deploy.startCommand:
sh -c 'echo "$GOOGLE_DRIVE_CREDENTIALS_JSON" > /tmp/google-drive-key.json && printf "{
  "agents": {
    "defaults": {
      "model": {
        "provider": "google",
        "model": "gemini-2.5-flash"
      },
      "agentRuntime": {
        "id": "pi"
      },
      "timeoutSeconds": 180
    }
  },
  "mcp": {
    "servers": {
      "google-drive": {
        "command": "npx",
        "args": ["-y", "@modelcontextprotocol/server-google-drive"],
        "env": {
          "GOOGLE_APPLICATION_CREDENTIALS": "/tmp/google-drive-key.json"
        }
      }
    }
  },
  "channels": {
    "telegram": {
      "dmPolicy": "open",
      "allowFrom": ["984052013"]
    }
  }
}" > /tmp/openclaw.json && export OPENCLAW_CONFIG_PATH=/tmp/openclaw.json && node openclaw.mjs gateway run --bind lan --port $PORT --allow-unconfigured'
